var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......왔군.","JPN":"……来たな。","ENG":"They're here.","TWN":"……來了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOLDIER_REPLACER_NULL_NULL","text":{"KOREA":"지, 지휘관님! 외곽 방어선이 뚫렸습니다!","JPN":"し、指揮官！　外郭の防衛線が破られました！","ENG":"C-Commander! Our outer defense line is breaking!","TWN":"指，指揮官大人！週邊防禦網被突破了！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"호들갑 떨지 마! 이 정도의 전투가 벌어지는데 사령부에서 모를 리가 없다!","JPN":"騒ぐな！　司令部でこの規模の戦闘を把握していないはずがない！","ENG":"Stay calm. There's no way that the high command isn't aware of a battle of this scale.","TWN":"不要大驚小怪的！都發生了這樣的戰鬥，司令部不可能不知道的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"조금만 있으면 사령부 병력과 간부들이 지원하러 올 거야!","JPN":"もうじき司令部の兵力や幹部らが支援に駆け付ける！","ENG":"Just hold on, and the officers will bring reinforcements from the high command!","TWN":"過一會，司令部的兵力和幹部就會來支援的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"COMMANDER_REPLACER_NULL_NULL","text":{"KOREA":"근거리에 있는 다른 부대들도 곧 합류하러 올 거다! 조금만 버텨라!!","JPN":"近くにいる他の部隊も、間もなく合流するはずだ！　もう少しだけ耐えろ！！","ENG":"Other forces in the nearby areas will come join us as well! Just hold the line for a little longer!","TWN":"在附近的部隊也會支援我們的！再堅持一會！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SOLDIER_REPLACER_NULL_NULL","text":{"KOREA":"하, 하지만......","JPN":"で、ですが……","ENG":"B-but...","TWN":"但、但是……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"안녕, 비숍 재생체 나으리.","JPN":"こんにちは、ビショップ再生体さん。","ENG":"Hi there, Regenerated Bishop.","TWN":"你好，大主教再生體大人。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"이런 자리에서 만나게 돼서 유감이야.","JPN":"こんなところで会うなんて残念ね。","ENG":"I'm sorry that we have to meet like this.","TWN":"在這裡見到妳真是遺憾呢。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"당신에게 공적인 용무는 없지만, 이것도 뭐 개인적인 감정이라서 말이야.","JPN":"あなたに用はないけど、個人的に片づけなければならないことがあって。","ENG":"I just want you to know, I'm not doing this for a great cause. It's strictly personal, every single bit of it.","TWN":"找妳雖然沒有什麼公事要辦，但倒是有些私事要處理。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"당신도 딱히 리플레이서에게 살아 있는 컴퓨터 취급이나 받는 게 즐겁진 않겠지?","JPN":"あなたも、リプレイサーに物みたいな扱いをされて嬉しくはないでしょ？","ENG":"You don't exactly find it amusing to be treated as a walking computer by your colleagues, do you?","TWN":"妳應該也不怎麼高興被克隆集團當作一台活體機器來對待吧？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"그러니까 인심 쓰는 셈 치고 여기서 죽......","JPN":"だから、ここは一つ目をつぶって、死んで……","ENG":"So why don't you do us a favor and die here—","TWN":"所以就當作是對妳的仁慈，在這裡死了也……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"아니, 생각해 보니 어차피 진짜 리플레이서 비숍은 죽었잖아?","JPN":"いや、本物のリプレイサー・ビショップはすでに死んでるんだった。","ENG":"No, come to think of it, the real Replacer Bishop already died.","TWN":"不，仔細想想，反正真正的克隆大主教也死了對吧？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"그러니까...... 작동정지 시켜 줄게.","JPN":"だったら……作動停止してあげる。","ENG":"So... I'm going to turn you off for good,","TWN":"所以……就讓妳停止運轉吧。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"영원히, 다시는 켤 수 없도록.","JPN":"永遠に起動できないように。","ENG":"and make sure you don't go walking around ever again.","TWN":"讓妳永遠無法再啟動。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"대, 대장...... 너무 악당 같아......","JPN":"た、隊長……悪党みたい……","ENG":"C-Cap... You sounded like a very mean movie villain...","TWN":"隊，隊長……太像壞人了……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"너, 너도 그렇게 느꼈냐? 실은 나도......","JPN":"お、お前もそう思ったか？　実は俺も……","ENG":"I-I know, right? I was feeling the same...","TWN":"妳、妳也這麼覺得嗎？其實我也……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......서윤.","JPN":"……アオイ・シズカ。","ENG":"Seo Yoon.","TWN":"……徐芸。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"역시 네가 배신자였나?","JPN":"やはりあなたが裏切者だったか。","ENG":"So you turned against us.","TWN":"妳果然是叛徒嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"뭐, 이런 게 약자의 싸움이라는 거지.","JPN":"まあ、これが弱者の戦い方ってものよ。","ENG":"Well, this is how the weak fight.","TWN":"這是弱者的戰鬥方式。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"너무 나쁘게 생각 말라고.","JPN":"あまり悪く思わないでね。","ENG":"I hope you won't find it too despicable.","TWN":"請不要把它想得太糟。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"당신들과는 다르게 우리 같은 약자는 수단 방법을 가릴 여유가 없거든.","JPN":"あなたたちと違って、私たちのような弱者は手段を選んでる場合じゃないのよ。","ENG":"Unlike you, wimps like us have to win by any means necessary.","TWN":"和你們不一樣，我們這種弱者是無法選擇手段的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......미스틸테인까지 뜯어간 주제에 뻔뻔하기도 하군.","JPN":"……ミスティルテインまで盗んだくせに、図々しい。","ENG":"And you have the brass neck to say that when you stole Misteltein from us.","TWN":"……連米斯特丁都拿走了，妳還真是厚臉皮呢。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"하긴, 퀸도 네가 영원히 우리 편으로 남을 거라고 생각하진 않았던 것 같지만.","JPN":"まあクイーンも、あなたがずっと味方のままだとは思わなかったようだが。","ENG":"Then again, Queen didn't seem to think you'd stay on our side forever anyway.","TWN":"但是，女皇也沒想過妳會永遠留在我們這邊。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......비숍.","JPN":"……ビショップ。","ENG":"Bishop.","TWN":"……大主教。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......유미나.","JPN":"……ヤナギ・ミナ。","ENG":"Yoo Mina.","TWN":"……劉米娜。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"왠지 다시 만날 거란 예감은 들었지만......","JPN":"なんとなく再会の予感はしていたが……","ENG":"I thought we'd meet again someday,","TWN":"我總有種我們會再見面的預感……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"정말로 여기까지 올 수 있을 줄은 몰랐어.","JPN":"本当にここまで来るとは。","ENG":"but really, I'm surprised that you've made it this far.","TWN":"但沒想到妳真的會來這裡。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"그래서...... 너도 날 죽이러 온 건가?","JPN":"それで……あなたも私を殺しに来たのか？","ENG":"So you're here to kill me?","TWN":"所以……妳也是來殺我的嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"내 모체를 죽였던 것처럼?","JPN":"私の母体を殺したように？","ENG":"Like you killed my source?","TWN":"就像殺掉我的母體那樣？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"묻고 싶은 게 있어.","JPN":"聞きたいことがあるの。","ENG":"I have something to ask you.","TWN":"我有事情想問妳。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"정말로...... 널 쓰러트리면 테라사이드 시스템을 멈출 수 있는 건가?","JPN":"本当に……あんたを倒せば、テラサイドシステムを止められるの？","ENG":"Is it true that System Terraside stops when you die?","TWN":"只要……只要擊敗了妳，真的可以停止特拉賽德系統嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"그게 궁금한가......?","JPN":"それが気になるのか……？","ENG":"Why do you ask?","TWN":"妳想知道這件事……？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"내 모체와 싸울 때도 그렇고, 넌 어쩔 수 없는 상황에 떠밀려 가려는 경향이 있군.","JPN":"私の母体と戦うときもそうだったが、あなたはやむを得ない雰囲気に流される傾向がある。","ENG":"It was the same when you fought my source, but you have a tendency to base your actions on circumstantial reasons.","TWN":"妳和我的母體戰鬥時也是這樣，都是被逼到無可奈何的情況呢。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"중요한 건 어디까지나 네 의지일 텐데?","JPN":"大事なのは、あくまであなたの意思ではないか？","ENG":"Isn't it your own will that matters?","TWN":"重要的應該是妳的意志不是嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"테라사이드 같은 게 무슨 상관이지?","JPN":"テラサイドと何の関係がある？","ENG":"Why does System Terraside have to matter at all?","TWN":"和特拉賽德系統有什麼關係呢？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"무슨 소릴 하는 거야?! 당연히 상관이 있지......!","JPN":"なに言ってるの！？　当然関係あるよ……！","ENG":"What are you talking about? Of course it matters!","TWN":"妳在說什麼？！當然有關了……！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......원한다면 대답해 주지.","JPN":"……望むなら答えよう。","ENG":"I'll tell you, if that's what you're curious about.","TWN":"……妳想知道的話我就告訴妳。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"동결처리 중인 리플레이서 룩을 제외하면, 현재 테라사이드 시스템 통제 코드를 빌드할 수 있는 건 나뿐이다.","JPN":"凍結処理中のリプレイサー・ルークを除けば、\\n現在テラサイドシステムの統制コードを構築できるのは、私だけ。","ENG":"Except for the Replacer Rook, who is currently under cryopreservation, I'm the only one who can build the control code for System Terraside.","TWN":"除了正在解凍的克隆．城堡，現在能夠生成特拉賽德系統控制代碼的就只有我。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"사령관인 리플레이서 킹도 그건 불가능하지.","JPN":"司令官であるリプレイサー・キングですら、構築はできない。","ENG":"It's something even King, our commander, cannot do.","TWN":"即使是司令官克隆．帝皇也無法做到。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"리플레이서 룩을 깨운다고 해도 지금처럼 전 지구적인 테라포밍을 진행할 만큼의 병렬연산은 처리할 수 없을 거다.","JPN":"リプレイサー・ルークを呼び起こしても、\\n今のように地球全体のテラフォーミングを行うほどの並列演算はできない。","ENG":"Even if they were to bring Replacer Rook back, it'd be impossible for them to handle the parallel calculations as complicated as the ongoing global terraforming process.","TWN":"但就算是克隆．城堡覺醒了，也沒辦法處理現在全球外星環境地球化的並行運算。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"그러니까......","JPN":"だから……","ENG":"So in short...","TWN":"所以……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"네 말대로 나만 죽일 수 있다면 리플레이서가 목표로 하는 테라사이드 프로젝트는 완수할 수 없다.","JPN":"あなたの言うとおり、私さえ始末できれば、\\nリプレイサーが目標にしているテラサイドプロジェクトは完遂させることができない。","ENG":"The Replacers' Project Terraside cannot succeed if I die, just like you said.","TWN":"妳說得沒錯，只要殺了我，克隆集團計畫的特拉賽德計畫就無法成功。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"들었지?","JPN":"聞いたよね？","ENG":"Hear that?","TWN":"聽到了吧？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"쓸데 없는 생각하지 말고 마음 단단히 먹어.","JPN":"余計なこと考えずに、覚悟を決めてよ。","ENG":"Now forget all the other crap and brace yourself.","TWN":"不要多想了，堅定一點。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"내 복수에 동참해 달라는 헛소리 따윌 할 생각은 없어.","JPN":"私の復讐に協力してなんて言うつもりはない。","ENG":"I'm not asking you to help me get my revenge.","TWN":"我也沒有想要妳加入我的復仇計畫。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"하지만 저 놈들은 지금도 전 세계를 실시간으로 오염시키고 있다고.","JPN":"あいつらは、今この瞬間にも世界中をリアルタイムで汚染しているんだよ。","ENG":"But those bastards are corrupting the entire world, even as we speak.","TWN":"但是那些人正在污染這個世界。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"그걸 막을 방법은 저 녀석을 쓰러트리는 것뿐이야.","JPN":"それを阻止する方法は、あいつを倒すことだけよ。","ENG":"Taking her down is the only way we can stop it.","TWN":"只有打倒這個傢伙才能阻止這一切。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......알고 있어.","JPN":"……わかってる。","ENG":"I know.","TWN":"……我知道。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나도...... 알고 있다고.","JPN":"私も……わかってるって。","ENG":"You don't have to remind me.","TWN":"我是……知道的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......결심이 섰나? 유미나.","JPN":"……覚悟を決めたか？　ヤナギ・ミナ。","ENG":"So is your mind made up now, Yoo Mina?","TWN":"……下定決心了嗎？劉米娜。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......그래.","JPN":"……うん。","ENG":"Yes.","TWN":"……對。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"......그렇군.","JPN":"……なるほど。","ENG":"I see.","TWN":"……是嗎。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"이제 나도 내 모체가 어떤 기분이었는지...... 알겠군.","JPN":"あの時、私の母体がどんな気持ちだったか……理解した。","ENG":"So this is how my source felt... I can finally see it.","TWN":"我的母體是什麼樣的心情……我現在好像懂了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"좋아. 덤벼라.","JPN":"始めよう。","ENG":"Fine. Bring it on.","TWN":"很好，放馬過來吧。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"하지만 나도 쉽게 죽어주진 않을 거야.","JPN":"だが、私も簡単には倒れたりはしない。","ENG":"I won't go down without a fight.","TWN":"但我也不會輕易被殺死的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"이래 보여도 리플레이서 5대 간부 중의 한 명이자 클리포트 인자를 베이스로 만들어진 진화 재생체다.","JPN":"これでも5大リプレイサーの幹部の一人で、クリフォト・ファクターを基に作られた進化再生体。","ENG":"I'm one of the five officers of the Replacers, and a regenerated hybrider evolved by the Qliphoth Factor.","TWN":"別看我這樣，我好歹也是克隆集團5大幹部之一，是在逆卡巴拉因子的基礎上被創造出來的進化再生體。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"후회가 남지 않게, 전력으로 싸우도록!","JPN":"悔いが残らないよう、全力で戦った方がいい！","ENG":"Leave no regrets. Come at me with everything you've got!","TWN":"不留遺憾，竭盡全力地戰鬥吧！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BISHOP_REPLACER_REGEN_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};